from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import os
import pickle

app = Flask(__name__)

# Load employee photos and encode faces
def load_employee_photos(directory):
    known_face_encodings = []
    known_face_names = []
    
    for filename in os.listdir(directory):
        if filename.endswith(".jpg") or filename.endswith(".png"):
            image = face_recognition.load_image_file(os.path.join(directory, filename))
            encoding = face_recognition.face_encodings(image)
            if encoding:
                known_face_encodings.append(encoding[0])
                known_face_names.append(os.path.splitext(filename)[0])
    
    return known_face_encodings, known_face_names

# Load the model
known_face_encodings, known_face_names = load_employee_photos('employee_photos')

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    file = request.files['image']
    image = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(image)

    if not face_encodings:
        return jsonify({'error': 'No face found in the image'}), 400

    face_encoding = face_encodings[0]
    distances = face_recognition.face_distance(known_face_encodings, face_encoding)
    probabilities = np.exp(-distances) / np.sum(np.exp(-distances))

    response = {name: float(prob) for name, prob in zip(known_face_names, probabilities)}
    return jsonify(response)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, ssl_context='adhoc')  # Use SSL for secure communication

# Save the model securely
with open('model.pkl', 'wb') as f:
    pickle.dump((known_face_encodings, known_face_names), f)